import MovieItem from "./MovieItem";

function MovieList({ movies, onDelete, onUpdate }) {
    return (
        <div>
            <h2>Movie List</h2>
            <ul>
                {movies.map((movie) => (
                    <MovieItem
                        key={movie.id}
                        movie={movie}
                        onDelete={onDelete}
                        onUpdate={onUpdate}   // ✅ IMPORTANT
                    />
                ))}
            </ul>
        </div>
    );
}

export default MovieList;
